import React, { useState, useEffect } from "react";
import axios from "axios";

const API = "http://localhost:8080";

const formatObj = (obj) => {
    if (obj == null) return "-";
    if (typeof obj === "object" && obj.id != null) return `${obj.nome ?? "N/A"} (id: ${obj.id})`;
    return String(obj);
};

const formatEndereco = (e) => {
    if (!e) return "-";
    const parts = [e.logradouro, e.numero, e.cidade, e.estado].filter(Boolean);
    return parts.length ? parts.join(", ") : "-";
};

function ListarTodosDados() {
    const [activeTab, setActiveTab] = useState("motoristas");
    const [motoristas, setMotoristas] = useState([]);
    const [idosos, setIdosos] = useState([]);
    const [enderecos, setEnderecos] = useState([]);
    const [relacionamentos, setRelacionamentos] = useState([]);
    const [loading, setLoading] = useState({ m: true, i: true, e: true, r: true });
    const [erro, setErro] = useState(null);

    useEffect(() => {
        setErro(null);
        axios.get(`${API}/motoristas`).then((r) => setMotoristas(r.data || [])).catch(() => setErro("Erro ao carregar motoristas")).finally(() => setLoading((l) => ({ ...l, m: false })));
        axios.get(`${API}/idosos`).then((r) => setIdosos(r.data || [])).catch(() => setErro("Erro ao carregar idosos")).finally(() => setLoading((l) => ({ ...l, i: false })));
        axios.get(`${API}/enderecos`).then((r) => setEnderecos(r.data || [])).catch(() => setErro("Erro ao carregar endereços")).finally(() => setLoading((l) => ({ ...l, e: false })));
        axios.get(`${API}/relacionamentos`).then((r) => setRelacionamentos(r.data || [])).catch(() => setErro("Erro ao carregar relacionamentos")).finally(() => setLoading((l) => ({ ...l, r: false })));
    }, []);

    const tabs = [
        { id: "motoristas", label: "Motoristas", loading: loading.m, data: motoristas },
        { id: "idosos", label: "Idosos", loading: loading.i, data: idosos },
        { id: "enderecos", label: "Endereços", loading: loading.e, data: enderecos },
        { id: "relacionamentos", label: "Relacionamentos", loading: loading.r, data: relacionamentos },
    ];

    return (
        <div className="listar-todos-dados">
            <h2 className="mb-4">Dados do sistema</h2>
            {erro && <div className="alert alert-warning">{erro}</div>}
            <ul className="nav nav-tabs mb-3">
                {tabs.map(({ id, label }) => (
                    <li className="nav-item" key={id}>
                        <button type="button" className={`nav-link ${activeTab === id ? "active" : ""}`} onClick={() => setActiveTab(id)}>
                            {label}
                        </button>
                    </li>
                ))}
            </ul>

            {activeTab === "motoristas" && (
                <div className="tab-pane">
                    {loading.m ? (
                        <p>Carregando motoristas...</p>
                    ) : (
                        <div className="table-responsive" style={{ overflowX: "auto", maxWidth: "100%" }}>
                            <table className="table table-striped table-bordered" style={{ minWidth: "max-content", whiteSpace: "nowrap" }}>
                                <thead className="table-dark">
                                    <tr>
                                        <th>Id</th>
                                        <th>Nome</th>
                                        <th>CPF</th>
                                        <th>Data Nasc.</th>
                                        <th>Telefone</th>
                                        <th>Email</th>
                                        <th>Ativo</th>
                                        <th>CNH</th>
                                        <th>COREN</th>
                                        <th>Serviços</th>
                                        <th>Disponível</th>
                                        <th>Aprovado</th>
                                        <th>Endereço origem</th>
                                        <th>Endereço destino</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {motoristas.length === 0 ? (
                                        <tr><td colSpan="14">Nenhum motorista cadastrado.</td></tr>
                                    ) : (
                                        motoristas.map((m) => (
                                            <tr key={m.id}>
                                                <td>{m.id}</td>
                                                <td>{m.nome ?? "-"}</td>
                                                <td>{m.cpf ?? "-"}</td>
                                                <td>{m.dataNascimento ?? "-"}</td>
                                                <td>{m.telefone ?? "-"}</td>
                                                <td>{m.email ?? "-"}</td>
                                                <td>{m.ativo ? "Sim" : "Não"}</td>
                                                <td>{m.cnh ?? "-"}</td>
                                                <td>{m.coren ?? "-"}</td>
                                                <td>{m.servicos ?? "-"}</td>
                                                <td>{m.disponivel ? "Sim" : "Não"}</td>
                                                <td>{m.aprovado ? "Sim" : "Não"}</td>
                                                <td>{formatEndereco(m.enderecoOrigem)}</td>
                                                <td>{formatEndereco(m.enderecoDestino)}</td>
                                            </tr>
                                        ))
                                    )}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            )}

            {activeTab === "idosos" && (
                <div className="tab-pane">
                    {loading.i ? (
                        <p>Carregando idosos...</p>
                    ) : (
                        <div className="table-responsive">
                            <table className="table table-striped table-bordered">
                                <thead className="table-dark">
                                    <tr>
                                        <th>Id</th>
                                        <th>Nome</th>
                                        <th>CPF</th>
                                        <th>Data Nasc.</th>
                                        <th>Telefone</th>
                                        <th>Email</th>
                                        <th>Ativo</th>
                                        <th>Contato emergência</th>
                                        <th>Endereço origem</th>
                                        <th>Endereço destino</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {idosos.length === 0 ? (
                                        <tr><td colSpan="10">Nenhum idoso cadastrado.</td></tr>
                                    ) : (
                                        idosos.map((i) => (
                                            <tr key={i.id}>
                                                <td>{i.id}</td>
                                                <td>{i.nome ?? "-"}</td>
                                                <td>{i.cpf ?? "-"}</td>
                                                <td>{i.dataNascimento ?? "-"}</td>
                                                <td>{i.telefone ?? "-"}</td>
                                                <td>{i.email ?? "-"}</td>
                                                <td>{i.ativo ? "Sim" : "Não"}</td>
                                                <td>{i.contatoEmergencia ?? "-"}</td>
                                                <td>{formatEndereco(i.enderecoOrigem)}</td>
                                                <td>{formatEndereco(i.enderecoDestino)}</td>
                                            </tr>
                                        ))
                                    )}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            )}

            {activeTab === "enderecos" && (
                <div className="tab-pane">
                    {loading.e ? (
                        <p>Carregando endereços...</p>
                    ) : (
                        <div className="table-responsive">
                            <table className="table table-striped table-bordered">
                                <thead className="table-dark">
                                    <tr>
                                        <th>Id</th>
                                        <th>Logradouro</th>
                                        <th>Número</th>
                                        <th>Cidade</th>
                                        <th>Estado</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {enderecos.length === 0 ? (
                                        <tr><td colSpan="5">Nenhum endereço cadastrado.</td></tr>
                                    ) : (
                                        enderecos.map((e) => (
                                            <tr key={e.id}>
                                                <td>{e.id}</td>
                                                <td>{e.logradouro ?? "-"}</td>
                                                <td>{e.numero ?? "-"}</td>
                                                <td>{e.cidade ?? "-"}</td>
                                                <td>{e.estado ?? "-"}</td>
                                            </tr>
                                        ))
                                    )}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            )}

            {activeTab === "relacionamentos" && (
                <div className="tab-pane">
                    {loading.r ? (
                        <p>Carregando relacionamentos...</p>
                    ) : (
                        <div className="table-responsive">
                            <table className="table table-striped table-bordered">
                                <thead className="table-dark">
                                    <tr>
                                        <th>Id</th>
                                        <th>Motorista</th>
                                        <th>Idoso</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {relacionamentos.length === 0 ? (
                                        <tr><td colSpan="3">Nenhum relacionamento cadastrado.</td></tr>
                                    ) : (
                                        relacionamentos.map((r) => (
                                            <tr key={r.id}>
                                                <td>{r.id}</td>
                                                <td>{formatObj(r.motorista)}</td>
                                                <td>{formatObj(r.idoso)}</td>
                                            </tr>
                                        ))
                                    )}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

export default ListarTodosDados;
